                clauses = [f"is {obj} metres"]
            else:
                clauses.append(f"has a {predicate} of {obj}")

        # If we have a special case for runwayLength, use that format
        if any(p == "runwayLength" for p, _ in triples):
            sentence = base_sentence + clauses[0] if clauses else base_sentence
        else:
            if clauses:
                sentence = f"{base_sentence} {', '.join(clauses)}"
            else:
                sentence = base_sentence

        sentences.append(sentence)

    # Join multiple sentences with appropriate connectors
    if len(sentences) == 1:
        return sentences[0] + "."
    else:
        # Try to create one complex sentence by finding relationships
        # For example: if A is in B, and B has a leader, combine them
        result = sentences[0]
        for i in range(1, len(sentences)):
            # Look for connections between subjects
            # If a sentence's object matches another subject, try to combine
            connected = False
            for j in range(i):
                # Check if current sentence's subject appears in previous sentence's object
                if sentences[j].find(sentences[i].split()[0]) != -1:
                    # Try to integrate
